problem_statement:
better error message when systematic has wrong number of bins for the channel

# Description

It's good that we can catch samples with wrong number of bins for a channel relatively early. We should catch this earlier too for systematics on the samples. Example here has a systematic with 3 bins for a channel with 4 bins:

```json
{
    "channels": [
        {
            "name": "SR",
            "samples": [
                {
                    "data": [
                        1,
                        2,
                        3,
                        4
                    ],
                    "modifiers": [
                        {
                            "data": null,
                            "name": "SigXsecOverSM",
                            "type": "normfactor"
                        }
                    ],
                    "name": "signal"
                },
                {
                    "data": [
                        2,
                        4,
                        6,
                        8
                    ],
                    "modifiers": [
                        {
                            "data": {
                                "hi_data": [
                                    3,
                                    6,
                                    9
                                ],
                                "lo_data": [
                                    1,
                                    2,
                                    3
                                ]
                            },
                            "name": "syst_wrongbins",
                            "type": "histosys"
                        }
                    ],
                    "name": "WtZ"
                }
            ]
        }
    ],
    "measurements": [
        {
            "config": {
                "parameters": [
                    {
                        "bounds": [
                            [
                                -10.0,
                                10.0
                            ]
                        ],
                        "fixed": true,
                        "inits": [
                            1.0
                        ],
                        "name": "SigXsecOverSM"
                    }
                ],
                "poi": "SigXsecOverSM"
            },
            "name": "NormalMeasurement"
        }
    ],
    "observations": [
        {
            "data": [
                2.0,
                2.0,
                2.0,
                2.0
            ],
            "name": "SR"
        }
    ],
    "version": "1.0.0"
}
```

